import { Routes } from '@angular/router';
import { LoginComponent } from './features/auth/login/login.component';
import { DashboardComponent } from './features/dashboard/dashboard.component';
import { DashboardHomeComponent } from './features/dashboard/dashboard-home/dashboard-home.component';
import { AlumnosComponent } from './features/dashboard/alumnos/alumnos.component';
import { CursosComponent } from './features/dashboard/cursos/cursos.component';
import { CursoDetalleComponent } from './features/dashboard/cursos/curso-detalle/curso-detalle.component';
import { authGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  { path: '', redirectTo: 'login', pathMatch: 'full' },
  { path: 'login', component: LoginComponent },
  { 
    path: 'dashboard', 
    component: DashboardComponent, 
    canActivate: [authGuard],
    children: [
      { path: '', component: DashboardHomeComponent },
      { path: 'alumnos', component: AlumnosComponent },
      { path: 'cursos', component: CursosComponent },
      { path: 'cursos/:id', component: CursoDetalleComponent }
    ]
  },
  { path: '**', redirectTo: 'login' }
];
